// --- Sync Manager for coordinating periodic sync ---

class SyncManager {
  final ApiClient _apiClient;
  Timer? _syncTimer;
  DateTime? _lastSyncedAt;
  bool _isSyncing = false;

  final StreamController<SyncResult> _syncResultController =
      StreamController<SyncResult>.broadcast();

  Stream<SyncResult> get syncResults => _syncResultController.stream;

  final StreamController<SyncError> _syncErrorController =
      StreamController<SyncError>.broadcast();

  Stream<SyncError> get syncErrors => _syncErrorController.stream;

  SyncManager({required ApiClient apiClient}) : _apiClient = apiClient;

  void startPeriodicSync({Duration interval = const Duration(minutes: 5)}) {
    stopPeriodicSync();
    _syncTimer = Timer.periodic(interval, (_) => performSync());
    // Perform an immediate sync as well
    performSync();
  }

  void stopPeriodicSync() {
    _syncTimer?.cancel();
    _syncTimer = null;
  }

  Future<SyncResult?> performSync({List<SyncData>? localChanges}) async {
    if (_isSyncing) return null;
    _isSyncing = true;

    try {
      final result = await _apiClient.syncData(
        localChanges: localChanges ?? [],
        lastSyncedAt: _lastSyncedAt,
      );

      _lastSyncedAt = result.syncedAt;
      _syncResultController.add(result);

      if (result.conflicts.isNotEmpty) {
        // Auto-resolve with server-wins strategy for simplicity
        final resolutions = result.conflicts
            .map((c) => {
                  'resource_id': c.resourceId,
                  'resource_type': c.resourceType,
                  'strategy': 'server_wins',
                })
            .toList();

        await _apiClient.resolveConflicts(resolutions: resolutions);
      }

      return result;
    } on ApiException catch (e) {
      _syncErrorController.add(SyncError(
        message: e.message,
        isRetryable: e.statusCode >= 500,
      ));
      return null;
    } on NetworkException catch (e) {
      _syncErrorController.add(SyncError(
        message: e.message,
        isRetryable: true,
      ));
      return null;
    } finally {
      _isSyncing = false;
    }
  }

  void dispose() {
    stopPeriodicSync();
    _syncResultController.close();
    _syncErrorController.close();
  }
}

class SyncError {
  final String message;
  final bool isRetryable;

  SyncError({required this.message, required this.isRetryable});
}

